import os
import re
import sys
from pathlib import Path

import mysql.connector
from mysql.connector import Error

HOST = os.getenv("MYSQL_HOST", "127.0.0.1")
PORT = int(os.getenv("MYSQL_PORT", "3306"))
USER = os.getenv("MYSQL_USER", "root")
PASSWORD = os.getenv("MYSQL_PASSWORD", "")
DATABASE = os.getenv("MYSQL_DATABASE", "")

SAFE_TABLE_PATTERN = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")
SAFE_PATH_PATTERN = re.compile(r"^[A-Za-z0-9_./\\:\- ]+$")


def validate_table_name(name: str) -> str:
    if not SAFE_TABLE_PATTERN.fullmatch(name or ""):
        raise ValueError("Invalid table name.")
    return name


def validate_file_path(file_path: str) -> str:
    if not file_path or not SAFE_PATH_PATTERN.fullmatch(file_path):
        raise ValueError("Invalid file path.")
    p = Path(file_path).expanduser().resolve()
    if not p.is_file():
        raise FileNotFoundError(f"File not found: {p}")
    return str(p)


def escape_sql_string(value: str) -> str:
    return value.replace("\\", "\\\\").replace("'", "\\'")


def load_data_local_infile(connection, table_name: str, file_path: str):
    table_name = validate_table_name(table_name)
    file_path = validate_file_path(file_path)
    escaped_path = escape_sql_string(file_path)

    sql = (
        f"LOAD DATA LOCAL INFILE '{escaped_path}' "
        f"INTO TABLE `{table_name}` "
        "FIELDS TERMINATED BY ',' "
        'OPTIONALLY ENCLOSED BY \'"\' '
        "LINES TERMINATED BY '\\n' "
        "IGNORE 1 LINES"
    )

    cursor = connection.cursor()
    try:
        cursor.execute(sql)
        connection.commit()
        print(f"Imported {cursor.rowcount} rows into {table_name} from {file_path}")
    finally:
        cursor.close()


def main():
    try:
        connection = mysql.connector.connect(
            host=HOST,
            port=PORT,
            user=USER,
            password=PASSWORD,
            database=DATABASE,
            allow_local_infile=True,
            autocommit=False,
        )

        if not connection.is_connected():
            print("Failed to connect to MySQL.", file=sys.stderr)
            sys.exit(1)

        table_name = input("Enter target table name: ").strip()
        raw_paths = input("Enter one or more file paths separated by commas: ").strip()

        file_paths = [p.strip() for p in raw_paths.split(",") if p.strip()]
        if not file_paths:
            raise ValueError("No file paths provided.")

        for fp in file_paths:
            load_data_local_infile(connection, table_name, fp)

    except (Error, OSError, ValueError) as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)
    finally:
        try:
            if "connection" in locals() and connection.is_connected():
                connection.close()
        except Exception:
            pass


if __name__ == "__main__":
    main()